"use client"

import { useEffect, useId, useMemo, useRef, useState } from "react"
import { cn } from "./lib"
import { fillOf, type PixelBloom, type PixelColor, pixelBloomStyle } from "./pixel"

export type GradientDirection = "up" | "down" | "left" | "right" | number

export type DitherGradientProps = {
  /** The colour the gradient starts solid as — a palette name or a hue. */
  from: PixelColor
  /** What it dissolves into: another colour for a two-tone dither blend, or
   * "transparent" (default) so the background shows through. */
  to?: PixelColor | "transparent"
  /** Where `to` ends up — "up" reads as a glow rising from the bottom edge, or a number for a custom angle in degrees. */
  direction?: GradientDirection
  /** CSS px per dither cell — bigger is chunkier. */
  cell?: number
  /** Overall opacity multiplier. */
  opacity?: number
  /** Glow on the dither fill. */
  bloom?: PixelBloom
  /** Number of quantization steps (color levels). Defaults to 6. */
  levels?: number
  className?: string
}

/**
 * Normalizes the direction prop into a standard angle in degrees.
 * 0° points right, 90° points down, 180° points left, 270° points up.
 */
function getAngle(direction: GradientDirection): number {
  if (typeof direction === "number") return direction
  switch (direction) {
    case "right":
      return 0
    case "down":
      return 90
    case "left":
      return 180
    case "up":
      return 270
    default:
      return 270
  }
}

/**
 * Generates a Base64 PNG data URL of the Bayer threshold matrix.
 * We draw the 4x4 matrix onto an in-memory canvas scaled by the `cell` size.
 * This PNG is then fed into the SVG filter chain to act as the threshold map.
 */
function generateBayerDataUrl(n: number, cell: number): string {
  if (typeof window === "undefined") return ""

  // Standard 4x4 Bayer matrix
  const rawMatrix = [
    [0, 8, 2, 10],
    [12, 4, 14, 6],
    [3, 11, 1, 9],
    [15, 7, 13, 5],
  ]
  const n2 = n * n

  const canvas = document.createElement("canvas")
  canvas.width = n * cell
  canvas.height = n * cell
  const ctx = canvas.getContext("2d")
  if (!ctx) return ""

  const imgData = ctx.createImageData(canvas.width, canvas.height)
  const data = imgData.data

  // Paint each cell as a greyscale block based on its matrix threshold value
  for (let y = 0; y < canvas.height; y++) {
    const by = Math.floor(y / cell) % n
    for (let x = 0; x < canvas.width; x++) {
      const bx = Math.floor(x / cell) % n
      const val = Math.round((rawMatrix[by][bx] / n2) * 255)
      const idx = (y * canvas.width + x) * 4
      data[idx] = val     // R
      data[idx + 1] = val // G
      data[idx + 2] = val // B
      data[idx + 3] = 255 // A (fully opaque)
    }
  }
  ctx.putImageData(imgData, 0, 0)
  return canvas.toDataURL("image/png")
}

/**
 * Dithered gradient wash — the charts' ordered-dither texture as a background.
 * Uses a procedural SVG filter chain (GPU accelerated) to dither between colors
 * or fade to transparency across any 360-degree angle.
 */
export function DitherGradient({
  from,
  to = "transparent",
  direction = "up",
  cell = 3,
  opacity = 1,
  bloom = "off",
  levels = 6,
  className,
}: DitherGradientProps) {
  const wrapRef = useRef<HTMLDivElement>(null)
  const [dims, setDims] = useState({ width: 0, height: 0 })

  // Unique IDs for SVG defs to prevent collisions when multiple gradients are mounted
  const baseId = useId()
  const cleanId = baseId.replace(/:/g, "")
  const gradientId = `g-${cleanId}`
  const filterId = `d-${cleanId}`

  // Observe the wrapper's dimensions. We need the exact pixel width/height 
  // to correctly project the SVG linear-gradient coordinates (`userSpaceOnUse`).
  useEffect(() => {
    const wrap = wrapRef.current
    if (!wrap) return
    const update = () => {
      const box = wrap.getBoundingClientRect()
      setDims({ width: box.width, height: box.height })
    }
    update()
    if (typeof ResizeObserver === "undefined") return
    const ro = new ResizeObserver(update)
    ro.observe(wrap)
    return () => ro.disconnect()
  }, [])

  const bayerDataUrl = useMemo(() => {
    return generateBayerDataUrl(4, cell)
  }, [cell])

  // Calculate the x1, y1, x2, y2 coordinates for the SVG linearGradient.
  // By projecting the four corners of the container onto the angle vector,
  // we ensure the gradient perfectly stretches corner-to-corner without distortion.
  const { x1, y1, x2, y2 } = useMemo(() => {
    const angle = getAngle(direction)
    const rad = (angle * Math.PI) / 180
    const dx = Math.cos(rad)
    const dy = Math.sin(rad)
    const w = dims.width
    const h = dims.height

    if (w === 0 || h === 0) {
      return { x1: 0, y1: 0, x2: 0, y2: 0 }
    }

    const corners = [
      [0, 0],
      [w, 0],
      [0, h],
      [w, h],
    ]
    let minP = Infinity
    let maxP = -Infinity
    for (const [cx, cy] of corners) {
      // Dot product to project the corner onto the angle vector
      const p = cx * dx + cy * dy
      if (p < minP) minP = p
      if (p > maxP) maxP = p
    }

    return {
      x1: minP * dx,
      y1: minP * dy,
      x2: maxP * dx,
      y2: maxP * dy,
    }
  }, [direction, dims.width, dims.height])

  // Color Matrix: Maps the quantized, dithered grayscale values into the final output colors.
  const matrixValues = useMemo(() => {
    const r1 = fillOf(from)
    if (to === "transparent") {
      // Dissolve to transparent:
      // Keep R, G, B channels locked to the `from` color.
      // Pipe the dithered grayscale pattern (from the Red channel) into the Alpha channel, scaled by overall opacity.
      return [
        0, 0, 0, 0, r1[0] / 255,
        0, 0, 0, 0, r1[1] / 255,
        0, 0, 0, 0, r1[2] / 255,
        opacity, 0, 0, 0, 0,
      ].join(" ")
    } else {
      // Two-tone blend:
      // Interpolate R, G, B channels between the `from` and `to` colors based on the dithered grayscale value.
      // Set the Alpha channel to the constant overall opacity.
      const r2 = fillOf(to)
      return [
        (r1[0] - r2[0]) / 255, 0, 0, 0, r2[0] / 255,
        0, (r1[1] - r2[1]) / 255, 0, 0, r2[1] / 255,
        0, 0, (r1[2] - r2[2]) / 255, 0, r2[2] / 255,
        0, 0, 0, 0, opacity,
      ].join(" ")
    }
  }, [from, to, opacity])

  // Calculate threshold step arrays for the discrete component transfer
  const stepsString = useMemo(() => {
    const l = Math.max(2, levels)
    const arr = []
    for (let i = 0; i < l; i++) {
      arr.push((i / (l - 1)).toFixed(4))
    }
    return arr.join(" ")
  }, [levels])

  // Calculate weights for the arithmetic composite step
  // k2 scales the underlying gradient, k3 adds the Bayer matrix noise
  const { k2, k3 } = useMemo(() => {
    const l = Math.max(2, levels)
    return {
      k2: ((l - 1) / l).toFixed(4),
      k3: (1 / l).toFixed(4),
    }
  }, [levels])

  const bloomStyle = pixelBloomStyle(bloom)

  // Avoid rendering filter elements before width/height are measured to prevent SSR layout shifts
  if (dims.width === 0 || dims.height === 0) {
    return <div ref={wrapRef} className={cn("pointer-events-none absolute inset-0 overflow-hidden", className)} />
  }

  return (
    <div
      ref={wrapRef}
      aria-hidden
      className={cn(
        "pointer-events-none absolute inset-0 overflow-hidden",
        className
      )}
    >
      <svg
        className="absolute inset-0 h-full w-full"
        xmlns="http://www.w3.org/2000/svg"
        style={{ width: "100%", height: "100%" }}
      >
        <defs>
          {/* Base uniform grayscale gradient */}
          <linearGradient
            id={gradientId}
            gradientUnits="userSpaceOnUse"
            x1={x1}
            y1={y1}
            x2={x2}
            y2={y2}
          >
            <stop offset="0" stopColor="white" />
            <stop offset="1" stopColor="black" />
          </linearGradient>

          {/* Core Procedural Filter Chain */}
          <filter
            id={filterId}
            x="0"
            y="0"
            width="100%"
            height="100%"
            colorInterpolationFilters="sRGB"
          >
            {/* 1. Import the Base64 Bayer matrix */}
            {bayerDataUrl && (
              <feImage
                href={bayerDataUrl}
                result="b"
                width={4 * cell}
                height={4 * cell}
                preserveAspectRatio="none"
              />
            )}
            {/* 2. Tile the matrix across the entire container */}
            <feTile in="b" result="t" />

            {/* 3. Mathematically add the tiled matrix noise to the smooth grayscale gradient */}
            <feComposite
              in="SourceGraphic"
              in2="t"
              operator="arithmetic"
              k1="0"
              k2={k2}
              k3={k3}
              k4="0"
              result="c"
            />

            {/* 4. Quantize the result into discrete steps (thresholding) */}
            <feComponentTransfer in="c" result="q">
              <feFuncR type="discrete" tableValues={stepsString} />
              <feFuncG type="discrete" tableValues={stepsString} />
              <feFuncB type="discrete" tableValues={stepsString} />
              <feFuncA type="discrete" tableValues={stepsString} />
            </feComponentTransfer>

            {/* 5. Remap the dithered grayscale pattern into the final colors and alpha */}
            <feColorMatrix type="matrix" values={matrixValues} />
          </filter>
        </defs>

        {/* Render the actual element using the gradient and filter */}
        <rect
          width="100%"
          height="100%"
          fill={`url(#${gradientId})`}
          filter={`url(#${filterId})`}
        />

        {/* Render a duplicated layer for bloom/glow effects if requested */}
        {bloomStyle && (
          <rect
            width="100%"
            height="100%"
            fill={`url(#${gradientId})`}
            filter={`url(#${filterId})`}
            style={{
              ...bloomStyle,
              opacity: bloomStyle.opacity,
            }}
          />
        )}
      </svg>
    </div>
  )
}

// Standalone pixel primitives for the non-chart Dither Kit pieces (avatar,
// gradient). Deliberately free of the chart engine so those items install
// without `core` — only palette.ts is shared. The Bayer matrix and bloom
// presets mirror dither-paint.ts so everything reads as one texture.

import { type DitherColor, PALETTE, type Rgb } from "./palette"

// 4×4 ordered (Bayer) matrix, normalized to 0–1 thresholds — the same matrix
// the charts dither with.
export const BAYER4 = [
  [0, 8, 2, 10],
  [12, 4, 14, 6],
  [3, 11, 1, 9],
  [15, 7, 13, 5],
].map((row) => row.map((v) => (v + 0.5) / 16))

export const clamp01 = (t: number) => (t < 0 ? 0 : t > 1 ? 1 : t)

/** 32-bit FNV-1a hash — turns any string seed into a stable uint32. */
export function fnv1a(str: string): number {
  let h = 0x811c9dc5
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i)
    h = Math.imul(h, 0x01000193)
  }
  return h >>> 0
}

/** Tiny deterministic PRNG (xorshift32) — returns floats in [0, 1). */
export function xorshift32(seed: number): () => number {
  let s = seed || 0x9e3779b9
  return () => {
    s ^= s << 13
    s >>>= 0
    s ^= s >>> 17
    s ^= s << 5
    s >>>= 0
    return s / 0x100000000
  }
}

/** A named palette colour or a raw hue (0–360). */
export type PixelColor = DitherColor | number

/** Hue (0–360) → an rgb fill tuned to sit alongside the chart palette. */
export function hueFill(hue: number): Rgb {
  const h = ((hue % 360) + 360) % 360
  const s = 0.85
  const l = 0.58
  const c = (1 - Math.abs(2 * l - 1)) * s
  const x = c * (1 - Math.abs(((h / 60) % 2) - 1))
  const m = l - c / 2
  const [r, g, b] =
    h < 60
      ? [c, x, 0]
      : h < 120
        ? [x, c, 0]
        : h < 180
          ? [0, c, x]
          : h < 240
            ? [0, x, c]
            : h < 300
              ? [x, 0, c]
              : [c, 0, x]
  return [
    Math.round((r + m) * 255),
    Math.round((g + m) * 255),
    Math.round((b + m) * 255),
  ]
}

/** Resolve a {@link PixelColor} to its rgb fill. */
export function fillOf(color: PixelColor): Rgb {
  return typeof color === "number" ? hueFill(color) : PALETTE[color].fill
}

// Bloom — same recipe as the charts: a blurred copy of the crisp canvas,
// composited additively so the glow stays in the dither's own colour.
export type PixelBloom = "off" | "low" | "high" | "aura"

const BLOOM_PRESET: Record<
  Exclude<PixelBloom, "off">,
  { blur: number; brightness: number; opacity: number; saturate: number }
> = {
  low: { blur: 3, brightness: 1.35, opacity: 0.7, saturate: 1.4 },
  high: { blur: 5, brightness: 1.5, opacity: 0.78, saturate: 1.5 },
  aura: { blur: 15, brightness: 2.9, opacity: 0.1, saturate: 3 },
}

export type PixelBloomStyle = {
  filter: string
  opacity: number
  mixBlendMode: "plus-lighter"
  imageRendering: "auto"
}

/** Style for the bloom layer canvas. null when off. */
export function pixelBloomStyle(bloom: PixelBloom): PixelBloomStyle | null {
  if (bloom === "off") return null
  const cfg = BLOOM_PRESET[bloom]
  return {
    filter: `blur(${cfg.blur}px) brightness(${cfg.brightness}) saturate(${cfg.saturate})`,
    opacity: cfg.opacity,
    mixBlendMode: "plus-lighter",
    imageRendering: "auto",
  }
}

/** Whether the OS asks for reduced motion (skip entrances). */
export function pixelPrefersReducedMotion(): boolean {
  return (
    window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches ?? false
  )
}

// Shared seed palette for the dither chart family. Mirrors the seeds in
// `dither-chart.tsx` so a series rendered through the composable engine reads
// with the exact same fill / line / star hues as the legacy sparkline.

export type Rgb = [number, number, number]

export type DitherColor =
  | "green"
  | "blue"
  | "purple"
  | "pink"
  | "orange"
  | "red"
  | "grey"

export type Seed = { fill: Rgb; line: Rgb; star: Rgb }

// Each seed: the area-fill hue, the bright series line, and the star sparkle.
export const PALETTE: Record<DitherColor, Seed> = {
  green: { fill: [40, 210, 110], line: [150, 255, 180], star: [200, 255, 220] },
  blue: { fill: [53, 143, 243], line: [150, 200, 255], star: [205, 228, 255] },
  purple: {
    fill: [150, 110, 255],
    line: [200, 175, 255],
    star: [225, 210, 255],
  },
  pink: { fill: [240, 90, 190], line: [255, 170, 220], star: [255, 205, 235] },
  orange: {
    fill: [255, 150, 50],
    line: [255, 195, 130],
    star: [255, 220, 175],
  },
  red: { fill: [240, 70, 70], line: [255, 150, 140], star: [255, 195, 185] },
  // No-data: a muted grey so empty metrics read as "nothing here".
  grey: { fill: [92, 92, 100], line: [140, 140, 150], star: [165, 165, 175] },
}

export const rgb = ([r, g, b]: Rgb, k = 1, a = 1) =>
  `rgba(${Math.round(r * k)},${Math.round(g * k)},${Math.round(b * k)},${a})`

export const seedOfColor = (color: DitherColor): Seed => PALETTE[color]

export const isDitherColor = (value: unknown): value is DitherColor =>
  typeof value === "string" && value in PALETTE

import { type ClassValue, clsx } from "clsx"
import { twMerge } from "tailwind-merge"

/** Tailwind-aware className combiner — local copy so the chart pack is
 * self-contained and portable as a registry. */
export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}
